1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	interface Item {
13	  type: string;
14	}
15	
16	interface Step {
17	  op: string;
18	  items?: Item[];
19	}
20	
21	interface Scenario {
22	  customer: { yearsWithMHPCO: number };
23	  steps: Step[];
24	}
25	
26	const sumBasePremiums = (items: Item[]): number =>
27	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
28	
29	const applyFirstInsuranceSurcharge = (base: number): number =>
30	  Math.ceil((base * (100 + FIRST_INSURANCE_PERCENT)) / 100);
31	
32	const quotePremium = (items: Item[]): number =>
33	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
34	
35	const executeStep = (step: Step): { premium: number } => ({
36	  premium: quotePremium(step.items ?? []),
37	});
38	
39	export const runScenario = (input: unknown): { results: unknown[] } => {
40	  const scenario = input as Scenario;
41	  return { results: scenario.steps.map(executeStep) };
42	};
